  ('089166f1-440a-536d-aa6b-013caf410db9','7526f789-dbdb-5603-852d-c4845096ab38','12/11/2025 16:53:48','vs Cádiz','#6 de perfil físico mediano, al que no veo destacar en nada más allá de carácter/liderazgo','NB',NULL),
  ('009f1262-414b-550d-b7b5-9fe350e0087e','98a9b155-2038-52c0-b0da-1055c9b14033','12/11/2025 16:55:10','vs Cádiz','Delantero centro referencia. #9 de área, fuerte, grande, juega de espaldas. Da sensación de tosco, no tiene tanto impacto en juego','NB',NULL),
