  ('2a1d88d6-bde4-5d9e-95e8-92949b1a1d5e','43479982-bcdd-5184-b814-a84af3ab5dba','12/11/2025 16:59:17','vs Cádiz','Central diestro, juega por izquierda. Perfil físico excelente, buena salida de balón, sólido en acciones defensivas. Tiene potencial de primer nivel.','NB','Firmar'),
  ('a9e0a222-50dc-57ce-a847-33ac4aec9d79','baa7b263-58d2-539e-83f3-3f79e10054fd','12/11/2025 17:03:57','vs Cádiz','Debut en Juvenil DH. Pocos minutos, poco impacto. Parece de físico hecho.','NB',NULL),
